const wh = $('Webhook: agent7').first();
const body = wh.json.body || wh.json;
const leadId = String(body.lead_id || '').trim();
if (!leadId) return [{ json: { error: 'no_lead_id', lead_id: '' } }];
const leadsRows = $input.all().map(i => i.json);
const leadRow = leadsRows.find(r => String(r.lead_id || '').trim() === leadId) || {};
return [{json:{ lead_id: leadId, lead: leadRow, website_url: leadRow.website || leadRow.url || '' }}];

// Agent 7 — Node: "Website-Prompt bauen"
// TASTE-SKILL: Homepage = Verkaufsprodukt. Restaurantinhaber muss denken "das will ich".
// Input: 1 item with full lead data (+ optional original site HTML from prev node)
// Output: 1 item with llm_payload

const data       = $input.first().json;
const leadId     = data.lead_id;
const lead       = data.lead       || {};
const content    = data.content    || {};
const images     = data.images     || {};
const concept    = data.concept    || {};
const promptData = data.prompt_data || {};

// Get original site HTML (continueOnFail)
let originalHtml = '';
try {
  const htmlNode = $('Original-URL fetchen').first();
  originalHtml = htmlNode.json.body || htmlNode.json.data || '';
  if (typeof originalHtml !== 'string') originalHtml = '';
  originalHtml = originalHtml.slice(0, 2000);
} catch(e) {}

// Resolve design data — prefer concept.json, fallback to prompt_data
const pos    = concept.positionierung   || {};
const tokens = concept.design_tokens    || {};
const copy   = concept.copy             || {};
const secs   = concept.sections         || [];
const ap     = concept.asset_plan       || {};
const constr = concept.constraints      || {};
const conv   = concept.conversion_logic || {};

const colors = tokens.colors     || promptData.design_system?.colors || {};
const typo   = tokens.typography || promptData.design_system?.typography || {};

const direction    = pos.design_direction    || promptData.design_system?.typography?.design_direction || 'elegant_modern';
const fontHeading  = typo.font_heading       || 'Playfair Display';
const fontBody     = typo.font_body          || 'Lato';
const heroHeadline = copy.hero_headline      || promptData.copy_blocks?.hero_headline  || lead.name || '';
const heroSub      = copy.hero_subheadline   || promptData.copy_blocks?.hero_subheadline || '';
const ctaPrimary   = copy.cta_primary        || 'Tisch reservieren';
const improvements = (concept.improvements_vs_original || promptData.design_system?.improvements || []).slice(0, 5).join('; ');
const posStatement = pos.statement || pos.claim || '';
const mood         = pos.mood || pos.atmosphaere || '';

// Fakten aus content.json
const f   = content.fakten         || {};
const it  = content.interpretation || {};
const name       = f.name          || lead.name  || '';
const adresse    = f.adresse       || lead.address || '';
const telefon    = f.telefon       || lead.phone  || '';
const email      = f.email         || '';
const oeffnung   = f.oeffnungszeiten || '';
const ueber_uns  = it.ueber_uns    || content.ueber_uns || '';
const spezis     = (it.spezialitaeten || content.spezialitaeten || []).slice(0, 8).join(', ');
const kueche     = (it.kueche      || content.kueche || []).join(', ');
const reservUrl  = f.reservierung_url || '';

const doNotInvent = constr.do_not_invent || promptData.do_not_invent || [];
const demoText    = `Diese Website ist eine Demo-Präsentation von MONEYLAN für ${name || 'diesen Betrieb'}.`;

// Design direction specific guidance
const directionGuide = {
  traditional_german: `
DIRECTION: Traditional German — Warm, erdverbunden, Holz + Cremeweiß + tiefes Grün oder Kastanienbraun.
Typography: Serif für Headlines (Playfair Display oder Libre Baskerville), Großzügige Abstände.
Layout: Asymmetrisch — große linke Text-Kolumne + rechts Bild, kein Grid-Template.
Hero: Dunkles Overlay auf Hintergrundbild (gradient bottom-to-top), Headline links, großgeschrieben.
Atmosphere: Gemütlich, historisch, vertrauenswürdig. Holztextur-Feeling durch Farbe, nicht durch echte Bilder.`,

  modern_bistro: `
DIRECTION: Modern Bistro — Schwarz + Weiß + 1 starker Akzent (Terrakotta, Senfgelb oder Mintgrün).
Typography: Editorial — Extra-Large Sans (Inter oder DM Sans, 900 weight), Kontrast klein/groß.
Layout: Bold split-screen Hero. Bento-Grid für Highlights. Viel Weißraum.
Hero: Links volle Höhe Bild, rechts Headline extrem groß (clamp(3rem,8vw,7rem)), minimal.
Atmosphere: Urban, curated, Instagram-worthy. Wenig Text, viel Raum.`,

  italian_traditional: `
DIRECTION: Italian Traditional — Off-white + Dunkelgrün + Gold-Akzent. Mediterrane Wärme.
Typography: Serif Italic für Hero (Cormorant Garamond oder EB Garamond), Body humanist sans.
Layout: Centered für den Hero ausnahmsweise erlaubt (einzige Ausnahme), dann Links-Rechts wechseln.
Hero: Voll-Bild mit Vignette, zentrierte Headline in Kursiv, elegant.
Atmosphere: La dolce vita, Familie, Handwerk.`,

  elegant_modern: `
DIRECTION: Elegant Modern — Dunkel (fast Schwarz) + Creme/Ivory + Gold oder Kupfer-Akzent.
Typography: Kontrast — Thin für Labels, Bold für Headlines. Mix Serif + Sans.
Layout: Luxury editorial. Breite Sections, Sticky Nav.
Hero: Volle Bildschirmhöhe. Headline unten-links (position absolute), Gradient Overlay.
Atmosphere: Fine Dining, exklusiv, leise Qualität.`,

  casual_friendly: `
DIRECTION: Casual Friendly — Lebendige Farben, rund, einladend. 2-3 Farben harmonisch.
Typography: Runde Sans-Serif (Nunito, Poppins), große Buttons.
Layout: Card-basiert aber NICHT generisch — Cards leicht rotiert, Schatten interessant.
Hero: Große Illustration oder Flat-Color-Block, Headline fett und nah.
Atmosphere: Herzlich, lokal, für alle.`
};

const dirGuide = directionGuide[direction] || directionGuide['elegant_modern'];

// Sections plan
const sectionsList = secs.length > 0
  ? secs.map(s => s.id || s.order).join(', ')
  : 'hero, highlights, about, contact, footer';

function safeColor(c) { return (c && typeof c === 'string') ? c : '#888'; }
const colorBlock = `primary: ${safeColor(colors.primary)}, secondary: ${safeColor(colors.secondary)}, accent: ${safeColor(colors.accent)}, bg: ${safeColor(colors.background)}, text: ${safeColor(colors.text)}`;

// ---- System prompt — TASTE-SKILL Edition ----
const systemPrompt = `You are an elite frontend engineer building a SALES DEMO website for a German restaurant.

MISSION: This demo is a sales tool. A restaurant owner will see it and decide whether to hire MONEYLAN.
The site must be visually STUNNING on first impression. It must feel better than their current website.
This is not a generic template. This is a premium, custom, restaurant-specific work of art.

OUTPUT FORMAT: Return ONLY valid JSON — no markdown, no explanation, no code fences:
{"files":[{"name":"path/to/file","content":"raw file content"}]}

═══ TASTE-SKILL: ABSOLUTE DESIGN RULES ═══

ANTI-PATTERNS — NEVER DO THESE:
× No centered hero text (except Italian Traditional direction)
× No generic teal/blue color schemes unless in design tokens
× No placeholder "Lorem ipsum" or generic text
× No stock-photo-style card grids (3 equal cards in a row)
× No rounded buttons with gradient backgrounds
× No clip art icons — use unicode symbols or SVG only
× No "Welcome to [Name]" hero headline
× No top-heavy layouts where everything is in the first 200px

PREMIUM PATTERNS — ALWAYS DO:
✓ Left-aligned or split-screen heroes (position: absolute text over image)
✓ Editorial typography: clamp() for responsive font-size, line-height 1.1–1.2 for display text
✓ CSS custom properties for ALL design tokens (--color-primary, --font-heading, etc.)
✓ Sticky demo banner at absolute top, non-dismissable, subtle
✓ Smooth scroll-triggered entry animations (IntersectionObserver, not framer-motion)
✓ One strong accent color used consistently — not sprinkled everywhere
✓ Real content hierarchy: 1 big thing per section, not 6 equal things
✓ Mobile-first: hamburger nav, hero height 100dvh on mobile

═══ HARD RULES ═══
1. No em-dashes (—). Use comma or nothing.
2. ALL Nav links → onClick={() => setModalOpen(true)} — opens InterestedModal
3. DemoNotice: sticky top-0 z-50 banner, non-dismissable
4. index.html: <meta name="robots" content="noindex,nofollow"> in <head>
5. Hero max 4 elements. Fits in 100dvh without scroll.
6. All CSS transitions: cubic-bezier(.23,1,.32,1), max 300ms
7. Missing data → "Auf Anfrage". NEVER invent: hours, prices, menu, address, phone
8. border-radius max 16px on cards
9. Button tap: scale(0.97) + 100ms ease-out
10. Google Fonts via @import in CSS (not link tag)

REQUIRED PACKAGES: react, react-dom, framer-motion
devDeps: vite, @vitejs/plugin-react, tailwindcss, autoprefixer, postcss`;

// ---- User prompt — TASTE-SKILL Edition ----
const userPrompt = `Build a premium sales demo for: ${name || leadId}
Lead ID: ${leadId}

═══ DESIGN DIRECTION: ${direction.toUpperCase()} ═══
${dirGuide}

DESIGN TOKENS (use as CSS custom properties):
Colors: ${colorBlock}
Font heading: ${fontHeading}
Font body: ${fontBody}

BRAND POSITIONING:
${posStatement ? `Claim: "${posStatement}"` : ''}
${mood ? `Atmosphere: ${mood}` : ''}
Hero headline: "${heroHeadline}"
Hero subheadline: "${heroSub}"
CTA primary: "${ctaPrimary}"
${improvements ? `Improvements vs. original: ${improvements}` : ''}

FACTS (use exactly — do not change):
Name: ${name || 'Auf Anfrage'}
Address: ${adresse || 'Auf Anfrage'}
Phone: ${telefon || 'Auf Anfrage'}
Email: ${email || 'Auf Anfrage'}
Hours: ${oeffnung || 'Auf Anfrage'}
Reservations: ${reservUrl || telefon || 'Auf Anfrage'}

CONTENT:
About: ${ueber_uns ? ueber_uns.slice(0, 500) : 'Auf Anfrage'}
Specialties: ${spezis || 'Auf Anfrage'}
Cuisine type: ${kueche || 'Auf Anfrage'}

DO NOT INVENT: ${doNotInvent.join(', ') || 'öffnungszeiten, preise, menü, adresse, telefon'}
Demo notice text: "${demoText}"
Sections to include: ${sectionsList}

HOMEPAGE = SALES PRODUCT:
The restaurant owner is the user. Make them think: "I want this for my real website."
The hero must be the MOST impressive thing they've ever seen for their restaurant.
Every section headline should be compelling, not informational.

REQUIRED FILES (generate ALL, no exceptions):
package.json
vite.config.js
tailwind.config.js
postcss.config.js
index.html
src/main.jsx
src/App.jsx
src/styles/tokens.css
src/data/site.js
src/components/Nav.jsx
src/components/DemoNotice.jsx
src/components/Hero.jsx
src/components/Highlights.jsx
src/components/About.jsx
src/components/Contact.jsx
src/components/Footer.jsx
src/components/InterestedModal.jsx

site.js = single source of truth for ALL data. App.jsx manages modalOpen state.
tokens.css defines ALL CSS custom properties. Main CSS imports tokens.css first.`;

const llmPayload = {
  model: 'Claude-Sonnet-4.6',
  messages: [
    { role: 'user', content: userPrompt },
  ],
  max_tokens: 12000,
  temperature: 0.3,
  system: systemPrompt,
};

return [{json: {
  lead_id:      leadId,
  lead:         lead,
  content:      content,
  images:       images,
  concept:      concept,
  llm_payload:  llmPayload,
  name:         name,
  demo_text:    demoText,
  do_not_invent: doNotInvent,
}}];

var data=$('Website-Prompt bauen').first().json;
var response=$input.first().json;
var rawContent=(response.choices&&response.choices[0]&&response.choices[0].message&&response.choices[0].message.content)||response.content||'';
var files=[],parseError=null,seen={};

// Normalize file name: strip leading 'N. ' prefix, trim whitespace
function normName(n){
  return String(n||'').replace(/^\d+\.\s+/,'').trim();
}

function addFile(name,content){
  name=normName(name);
  if(!name||seen[name])return;
  seen[name]=true;
  files.push({name:name,content:content});
}

// Strategy 1: XML <file name="...">...</file>
var xmlRe=/<file\s+name="([^"]+)">\n?((?:[\s\S])*?)<\/file>/g,m;
while((m=xmlRe.exec(rawContent))!==null) addFile(m[1],m[2]);

// Strategy 2: Markdown code blocks - ALL heading/bold formats
if(files.length===0){
  var parts=rawContent.split(/\n```/);
  for(var i=1;i<parts.length;i+=2){
    var before=parts[i-1];
    var block=parts[i];
    var nl=block.indexOf('\n');if(nl===-1)continue;
    var content=block.slice(nl+1);
    var rn=null;
    // Format A: **filename**
    var bm=before.match(/\*\*([^*\n]+?)\*\*/g);
    if(bm) rn=bm[bm.length-1].replace(/\*\*/g,'').trim();
    // Format B: ### `filename`
    if(!rn){var hb=before.match(/#{1,4}\s+`([^`\n]+)`/g);if(hb){var lh=hb[hb.length-1].match(/`([^`\n]+)`/);if(lh)rn=lh[1].trim();}}
    // Format C: ### filename.ext
    if(!rn){var hp=before.match(/#{1,4}\s+([\w./\-]+\.[a-z]{1,5})/g);if(hp){var lp=hp[hp.length-1].match(/([\w./\-]+\.[a-z]{1,5})$/);if(lp)rn=lp[1].trim();}}
    // Format D: standalone filename line
    if(!rn){var lines=before.split('\n');for(var k=lines.length-1;k>=Math.max(0,lines.length-4);k--){var ln=lines[k].trim().replace(/^\d+\.\s+/,'');var fm=ln.match(/^[`*_]?([\w./\-]+\.(?:jsx?|tsx?|json|html|css|md))[`*_]?:?$/i);if(fm){rn=fm[1];break;}}}
    if(rn) addFile(rn,content);
  }
}

// Strategy 3: JSON {"files":[...]}
if(files.length===0){
  var cleaned=rawContent.replace(/```(?:json)?\n?/gi,'').replace(/```\n?/g,'').trim();
  var idx=cleaned.indexOf('{"files"');if(idx>-1){try{var p=JSON.parse(cleaned.slice(idx));if(p&&Array.isArray(p.files))p.files.forEach(function(f){if(f.name&&typeof f.content==='string')addFile(f.name,f.content);});}catch(e){}}
}

if(files.length===0)parseError='parse_failed_all_strategies';
else if(files.length<7)parseError='partial_files_'+files.length;

return [{json:Object.assign({},data,{files:files,parse_error:parseError,raw_length:rawContent.length,file_count_parsed:files.length})}];

var data=$input.first().json;
var leadId=data.lead_id;
var files=data.files||[];
var name=data.name||'Restaurant';
var demoText=data.demo_text||'Demo von MONEYLAN';
var telefon=(data.content&&data.content.telefon)||'';
var adresse=(data.content&&data.content.adresse)||'';

var STUBS={
  'postcss.config.js': 'export default { plugins: { tailwindcss: {}, autoprefixer: {} } };',

  // App.jsx passes ALL possible prop names so any generated component works
  'src/App.jsx': 'import React, { useState } from "react"; import DemoNotice from "./components/DemoNotice.jsx"; import Nav from "./components/Nav.jsx"; import Hero from "./components/Hero.jsx"; import About from "./components/About.jsx"; import Contact from "./components/Contact.jsx"; import Footer from "./components/Footer.jsx"; import InterestedModal from "./components/InterestedModal.jsx"; export default function App() { const [m, setM] = useState(false); const open = () => setM(true); const close = () => setM(false); const h = { onNavClick: open, onCtaClick: open, onCTAClick: open, onCta: open, openModal: open }; return (<div className="min-h-screen bg-bg font-body text-text"><DemoNotice /><Nav {...h} /><main><Hero {...h} /><About {...h} /><Contact {...h} /></main><Footer {...h} />{m && <InterestedModal onClose={close} isOpen={m} />}</div>); }',

  // DemoNotice: works with both site.demoNotice and plain text
  'src/components/DemoNotice.jsx': 'import React from "react"; import { site } from "../data/site"; export default function DemoNotice(){ return(<div className="sticky top-0 z-50 bg-primary text-secondary text-center text-xs sm:text-sm font-body py-2 px-4 tracking-wide shadow-md"><span className="font-semibold">{site.demoNotice||"Demo-Praesentation von MONEYLAN"}</span></div>);}',

  // InterestedModal: works with both site.contact.phone and site.phone
  'src/components/InterestedModal.jsx': 'import React from "react"; import { site } from "../data/site"; export default function InterestedModal({onClose,isOpen}){ var ph=(site.contact&&site.contact.phone)||site.phone||""; var addr=(site.contact&&site.contact.address)||site.address||""; return(<div className="fixed inset-0 z-50 flex items-center justify-center bg-text/60 backdrop-blur-sm px-4" onClick={onClose}><div className="bg-bg rounded-2xl shadow-2xl max-w-md w-full p-8 relative border border-primary/20" onClick={function(e){e.stopPropagation();}}><div className="absolute top-0 left-0 right-0 h-1 rounded-t-2xl bg-primary"/><button onClick={onClose} className="absolute top-4 right-4 text-primary/60 hover:text-primary text-2xl leading-none" aria-label="Schliessen">&times;</button><div className="flex justify-center mb-4"><span className="text-5xl">&#127869;</span></div><h2 className="font-heading text-2xl text-primary text-center mb-3">{site.cta||"Tisch reservieren"}</h2><p className="font-body text-text/80 text-center leading-relaxed mb-6">Wir freuen uns auf Ihren Besuch. Reservieren Sie direkt telefonisch.</p><div className="bg-secondary rounded-xl p-5 text-center mb-6 border border-primary/10">{ph&&(<a href={"tel:"+ph.replace(/\\s/g,"")} className="font-heading text-2xl text-primary hover:text-accent transition-colors block">{ph}</a>)}<p className="font-body text-text/60 text-sm mt-2">{addr}</p></div><button onClick={onClose} className="w-full py-3 rounded-xl bg-primary text-secondary font-heading text-sm tracking-widest uppercase hover:bg-primary/90 transition-colors">Schliessen</button></div></div>);}',

  // Footer: works with both site.contact.phone and site.phone
  'src/components/Footer.jsx': 'import React from "react"; import { site } from "../data/site"; export default function Footer({ openModal, onNavClick }){ var open=openModal||onNavClick||function(){}; var ph=(site.contact&&site.contact.phone)||site.phone||""; var addr=(site.contact&&site.contact.address)||site.address||""; return(<footer className="bg-text text-secondary py-12 px-6"><div className="max-w-5xl mx-auto text-center"><p className="font-heading text-xl mb-2">{site.name}</p>{addr&&<p className="font-body text-secondary/60 text-sm mb-4">{addr}</p>}{ph&&<a href={"tel:"+ph.replace(/\\s/g,"")} className="font-body text-secondary/80 text-sm hover:text-secondary block">{ph}</a>}<button onClick={open} className="mt-6 font-heading text-xs uppercase tracking-widest border border-secondary/30 text-secondary px-6 py-2 rounded-xl hover:bg-secondary/10 transition-all">{site.cta||"Tisch reservieren"}</button><div className="border-t border-secondary/10 mt-8 pt-6"><p className="font-body text-secondary/40 text-xs">{site.demoNotice}</p></div></div></footer>);}',

  // About stub (fallback if LLM version is truncated)
  'src/components/About.jsx': 'import React from "react"; import { site } from "../data/site"; export default function About(props){ var open=props.onNavClick||props.onCtaClick||props.onCta||function(){}; return(<section id="about" className="py-20 bg-secondary"><div className="max-w-5xl mx-auto px-6"><div className="text-center mb-12"><p className="font-body text-primary text-xs uppercase tracking-widest mb-3">Ueber uns</p><h2 className="font-heading text-3xl text-text mb-4">{site.name}</h2></div><div className="grid lg:grid-cols-2 gap-12 items-start"><div><p className="font-body text-text/80 text-lg leading-relaxed mb-8">{site.about||site.tagline||site.claim||""}</p><button onClick={open} className="font-heading text-xs uppercase tracking-widest bg-primary text-secondary px-8 py-3 rounded-xl hover:bg-primary/90">{site.cta||"Tisch reservieren"}</button></div><div className="grid grid-cols-2 gap-4">{(site.specialties||[]).map(function(s,i){return(<div key={i} className="bg-bg rounded-xl p-4 border border-primary/10 text-center"><p className="font-body text-text text-sm">{s}</p></div>);})}</div></div></div></section>);}',

  // Contact stub (fallback)
  'src/components/Contact.jsx': 'import React from "react"; import { site } from "../data/site"; export default function Contact(props){ var open=props.onNavClick||props.onCtaClick||props.onCta||function(){}; var ph=(site.contact&&site.contact.phone)||site.phone||""; var addr=(site.contact&&site.contact.address)||site.address||""; var hours=site.hours||[]; return(<section id="contact" className="py-20 bg-bg"><div className="max-w-5xl mx-auto px-6"><div className="text-center mb-12"><p className="font-body text-primary text-xs uppercase tracking-widest mb-3">Besuchen Sie uns</p><h2 className="font-heading text-3xl text-text mb-4">Kontakt</h2></div><div className="grid sm:grid-cols-2 gap-8"><div className="bg-secondary rounded-2xl p-8 border border-primary/10"><h3 className="font-heading text-primary text-lg font-bold mb-5">Kontakt</h3>{addr&&<p className="font-body text-text/70 text-sm mb-3">{addr}</p>}{ph&&<a href={"tel:"+ph.replace(/\\s/g,"")} className="font-heading text-2xl text-primary font-bold hover:text-accent block mb-4">{ph}</a>}<button onClick={open} className="font-heading text-xs uppercase tracking-widest bg-primary text-secondary px-6 py-2.5 rounded-xl hover:bg-primary/90">{site.cta||"Tisch reservieren"}</button></div><div className="bg-secondary rounded-2xl p-8 border border-primary/10">{hours.map(function(h){var rows=h.rows||h.times||h.schedule||[];return(<div key={h.area||h.name} className="mb-6 last:mb-0"><h3 className="font-heading text-primary text-base font-bold mb-3">{h.area||h.name}</h3><ul className="space-y-2">{rows.map(function(r){return(<li key={r.day} className="flex justify-between font-body text-sm text-text/70"><span>{r.day}</span><span className="font-semibold">{r.time}</span></li>);})}</ul></div>);})}</div></div></div></section>);}',
};

// Build file map
var fileMap={};
files.forEach(function(f){fileMap[f.name]=f.content;});

// Detect truncated files
function isTruncated(c){
  if(!c||c.length<20)return true;
  return !/[\};>)]\s*$/.test(c.trimEnd());
}

// Apply stubs for missing or truncated files
Object.keys(STUBS).forEach(function(req){
  var existing=fileMap[req];
  if(!existing||isTruncated(existing)){
    fileMap[req]=STUBS[req];
    var found=false;
    for(var i=0;i<files.length;i++){if(files[i].name===req){files[i].content=STUBS[req];found=true;break;}}
    if(!found) files.push({name:req,content:STUBS[req]});
  }
});

// Add src/index.css if missing
if(!fileMap['src/index.css']&&!fileMap['index.css']){
  var css='@tailwind base;\n@tailwind components;\n@tailwind utilities;\nbody{margin:0;}';
  files.push({name:'src/index.css',content:css});
}

// Build Vercel payload
var filesForVercel=files.map(function(f){
  return{file:f.name,data:Buffer.from(f.content,'utf8').toString('base64'),encoding:'base64'};
});
var projName='ml-'+leadId.replace(/[^a-z0-9-]/gi,'').toLowerCase().slice(0,40);
var vercelBody={name:projName,files:filesForVercel,projectSettings:{buildCommand:'npm run build',outputDirectory:'dist',framework:'vite',installCommand:'npm install'},target:'production'};

return [{json:Object.assign({},data,{vercel_body:vercelBody,file_count:files.length,site_dir:'vercel:'+projName,files_prepared:files.map(function(f){return f.name;})})}];

const writtenData = $('Files schreiben').first().json;
const vercelResp = $input.first().json;
const leadId = writtenData.lead_id;
var demoUrl = '', buildStatus = 'built';
if (vercelResp.url && !vercelResp.error) {
  demoUrl = 'https://' + vercelResp.url;
  buildStatus = 'deployed';
} else if (vercelResp.readyState === 'READY') {
  demoUrl = 'https://' + ((vercelResp.alias || [])[0] || vercelResp.id + '.vercel.app');
  buildStatus = 'deployed';
} else {
  demoUrl = '/files/runs/' + leadId + '/site/index.html';
  buildStatus = 'files_only';
}
return [{json:{ lead_id: leadId, demo_url: demoUrl, build_status: buildStatus, files_written: writtenData.files_written || [], site_dir: writtenData.site_dir, vercel_error: vercelResp.error || null, file_count: writtenData.file_count || 0 }}];

const leadData = $('Daten laden').first().json;
