const vercelResp = $input.first().json;
const leadId = writtenData.lead_id;
var demoUrl = '', buildStatus = 'built';
if (vercelResp.url && !vercelResp.error) {
  demoUrl = 'https://' + vercelResp.url;
  buildStatus = 'deployed';
} else if (vercelResp.readyState === 'READY') {
  demoUrl = 'https://' + ((vercelResp.alias || [])[0] || vercelResp.id + '.vercel.app');
  buildStatus = 'deployed';
} else {
  demoUrl = '/files/runs/' + leadId + '/site/index.html';
  buildStatus = 'files_only';
}
return [{json:{ lead_id: leadId, demo_url: demoUrl, build_status: buildStatus, files_written: writtenData.files_written || [], site_dir: writtenData.site_dir, vercel_error: vercelResp.error || null, file_count: writtenData.file_count || 0 }}];

const leadData = $('Daten laden').first().json;
const leadId = leadData.lead_id;
const conceptRows = $input.all().map(i => i.json);
const concept = conceptRows.find(r => String(r.lead_id || '').trim() === leadId) || {};
return [{json: Object.assign({}, leadData, { concept: concept })}];

const konzept = $('Konzept mergen').first().json;
const leadId = konzept.lead_id;
const contentRows = $input.all().map(i => i.json);
const content = contentRows.find(r => String(r.lead_id || '').trim() === leadId) || {};
return [{json: Object.assign({}, konzept, { content: content })}];

const prevData = $('Content mergen').first().json;
const leadId = prevData.lead_id;
const imagesRows = $input.all().map(i => i.json);

// Use LAST matching row (newest data, since Agent 3 appends on each run)
const matching = imagesRows.filter(r => String(r.lead_id || '').trim() === leadId);
const images = matching.length > 0 ? matching[matching.length - 1] : {};

return [{ json: Object.assign({}, prevData, { images: images }) }];
